module.exports = {
  config: {
cooldowns: 10,
credits: 'CHAND',
premium: false,
permission: 0,
version: '1.0.0',
    name: 'unsend',
    aliases: ['uns', 'del'],
    description: 'Unsend bot message',
    usage: 'unsend (reply to bot message)',
    category: 'Admin',
    adminOnly: true,
    prefix: true
  },
  
  async run({ api, event, send }) {
    const { messageReply } = event;
    
    if (!messageReply) {
      return send.reply('━❮🐉❯━━━❪💝❫━━━❮🐉❯━\n⚠️ 🅟𝐥𝐞𝐚𝐬𝐞 𝐫𝐞𝐩𝐥𝐲 𝐭𝐨 𝐚 𝐦𝐞𝐬𝐬𝐚𝐠𝐞 𝐭𝐨 𝐮𝐧𝐬𝐞𝐧𝐝.\n━❮🐉❯━━━❪💝❫━━━❮🐉❯━');
    }
    
    const botID = api.getCurrentUserID();
    
    if (messageReply.senderID !== botID) {
      return send.reply('━❮🐉❯━━━❪💝❫━━━❮🐉❯━\n⚠️ 🅘 𝐜𝐚𝐧 𝐨𝐧𝐥𝐲 𝐮𝐧𝐬𝐞𝐧𝐝 𝐦𝐲 𝐨𝐰𝐧 𝐦𝐞𝐬𝐬𝐚𝐠𝐞𝐬.\n━❮🐉❯━━━❪💝❫━━━❮🐉❯━');
    }
    
    try {
      await api.unsendMessage(messageReply.messageID);
    } catch (error) {
      return send.reply('Failed to unsend message.');
    }
  }
};
